/// Probability that an auto-mock should use an error variant instead of a
/// success variant. Applied per-dependency during exploration to exercise
/// error-handling paths.
pub const DEFAULT_ERROR_PROBABILITY: f64 = 0.15;

/// Category of an external dependency, used to select default mock behavior.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum IoCategory {
    /// File system operations (fs, path).
    FileSystem,
    /// Network operations (http, fetch, axios, net).
    Network,
    /// Database operations (pg, mysql, mongodb, redis, prisma, knex).
    Database,
    /// Pure utility functions (lodash, ramda, date-fns) — safe to call.
    PureUtility,
    /// Other external library — use type-aware stub.
    ExternalOther,
}

/// Known module prefixes for each category.
const FS_MODULES: &[&str] = &[
    "fs", "node:fs", "fs/promises", "node:fs/promises", "path", "node:path",
    // Go stdlib
    "os", "io", "io/ioutil", "bufio",
];
const NETWORK_MODULES: &[&str] = &[
    "http", "https", "node:http", "node:https", "net", "node:net",
    "axios", "node-fetch", "fetch", "got", "superagent", "request",
    "undici",

//! Shared types for type information and parameter metadata.

use serde::{Deserialize, Serialize};

/// Well-known complex types that go beyond primitives and structural types.
///
/// Every supported complex type is an explicit variant. Adding a new type
/// requires adding a variant here, a generator in input_gen.rs, and
/// declaring support in the relevant frontend's handshake capabilities.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ComplexKind {
    // ── Temporal ──
    Date,
    DateTime,
    Time,
    Duration,

    // ── Text / Pattern ──
    RegExp,
    Char,
    /// JS/TS Symbol.
    Symbol,

    // ── Extended Numeric ──
    BigInt,
    BigDecimal,
    /// Complex numbers (real + imaginary).
    Complex,
    Rational,
    Range,

    // ── Binary ──
    Buffer,
    BitSet,

    // ── Error / Result ──
    Error,
    /// Option/Maybe wrapper.
    Option,
    /// Result/Either wrapper.
    Result,

    // ── Functional ──
    Closure,
    Iterator,

    // ── Network / Web ──
    Url,
    IpAddress,

    // ── Serialization / Interchange ──
    Uuid,

    // ── I/O ──
    Path,

    // ── Domain-Specific ──
    Money,
    SemVer,
    Email,
    MimeType,
    Color,
    GeoPoint,
    Locale,

    // ── Go-specific ──
    /// Go rune (int32 alias for Unicode codepoint).
    Rune,
    /// Go byte (uint8 alias).
    GoByte,
}

/// Describes the type of a value, as reported by a language frontend.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum TypeInfo {
    Int,
    Float,
    Str,
    Bool,
    Array {
        element: Box<TypeInfo>,
    },
    Object {
        fields: Vec<(String, TypeInfo)>,
    },
    Union {
        variants: Vec<TypeInfo>,
    },
    Nullable {
        inner: Box<TypeInfo>,
    },
    /// Complex (non-primitive, non-collection) type.
    Complex {
        #[serde(rename = "complex_kind")]
        kind: ComplexKind,
        /// Language-specific metadata (e.g., `{"class":"TypeError"}`, `{"flags":"gi"}`).
        #[serde(default)]
        metadata: serde_json::Map<String, serde_json::Value>,
        /// Inner type for wrapper types (Option<T>, Result<T,E>).
        #[serde(default, skip_serializing_if = "Option::is_none")]
        inner: Option<Box<TypeInfo>>,
    },
    /// Runtime resource type that cannot be meaningfully constructed for testing
    /// (sockets, file descriptors, database connections, streams, channels).
    ///
    /// Distinct from `Unknown` (type couldn't be resolved) and `Complex` (type is
    /// known and constructible).
    Opaque {
        label: String,
    },
    /// Type could not be determined statically.
    Unknown,
}

impl TypeInfo {
    /// Returns `true` if this type tree contains an `Opaque` variant anywhere
    /// (directly or nested inside Array elements, Object fields, Union variants,
    /// Nullable inner, or Complex inner).

