//! Mock value space selection and live-first fallback logic.
//!
//! When Shatter encounters an external dependency during exploration, it must
//! decide how to provide return values. [`MockValueSpace`] captures the
//! available strategies; [`LiveFirstState`] implements a state machine that
//! attempts live calls first and falls back to synthetic mocks on connection
//! failure.

use serde::{Deserialize, Serialize};

// ---------------------------------------------------------------------------
// MockValueSpace — strategy for generating mock return values
// ---------------------------------------------------------------------------

/// Strategy for selecting mock return values during exploration.
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case", tag = "kind")]
pub enum MockValueSpace {
    /// Try the real service first; fall back to synthetic mocks on connection
    /// failure. This is the default for network/database dependencies.
    LiveFirst,
    /// Use a fixed set of user-provided return values (round-robin).
    FixedSet { values: Vec<serde_json::Value> },
    /// Engine generates values autonomously based on type information.
    Autonomous,
    /// Replay a recorded seed corpus (e.g. from a prior live session).
    Seeded { seed_file: String },
}

// ---------------------------------------------------------------------------
// Live call outcome classification
// ---------------------------------------------------------------------------

/// Coarse classification of a live call attempt.
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case", tag = "outcome")]
pub enum LiveCallOutcome {
    /// Call succeeded — the return value is usable.
    Success,
    /// Infrastructure-level failure — the service is unreachable.
    ConnectionFailure { kind: ConnectionFailureKind },
    /// Application-level error (e.g. HTTP 4xx/5xx) — service is reachable but
    /// returned an error. Still useful as an observed behavior.
    AppError { message: String },
}

/// Subcategories of connection failure, used for diagnostics and to decide
/// whether retries are worthwhile.
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ConnectionFailureKind {
    ConnectionRefused,
    DnsFailure,
    AuthError,
    Timeout,
    Other,
}

// ---------------------------------------------------------------------------
// Error heuristic patterns — named constants for substring matching
// ---------------------------------------------------------------------------

/// Patterns indicating a refused TCP connection.
pub const CONN_REFUSED_PATTERNS: &[&str] = &["ECONNREFUSED", "connection refused", "Connection refused"];

/// Patterns indicating a DNS resolution failure.
pub const DNS_FAILURE_PATTERNS: &[&str] = &[
    "ENOTFOUND",
    "EAI_AGAIN",
    "dns resolution",
    "DNS resolution",
    "getaddrinfo",
    "no such host",
];

/// Patterns indicating an authentication/authorization failure.
pub const AUTH_ERROR_PATTERNS: &[&str] = &[
    "EAUTH",
    "authentication failed",
    "unauthorized",
    "403 Forbidden",
    "401 Unauthorized",
    "invalid credentials",
];

/// Patterns indicating a timeout.
pub const TIMEOUT_PATTERNS: &[&str] = &[
    "ETIMEDOUT",
    "ESOCKETTIMEDOUT",
    "ETIME",
    "timed out",
    "timeout",
    "deadline exceeded",
];

/// HTTP status codes that indicate application-level errors (not infra).
pub const APP_ERROR_STATUS_CODES: &[&str] = &["400 ", "404 ", "409 ", "422 ", "500 ", "502 ", "503 "];

// ---------------------------------------------------------------------------
// Classification functions
// ---------------------------------------------------------------------------

/// Classify an error message as a specific connection failure kind.
///
/// Returns `None` if the message doesn't match any known connection failure
/// pattern (it may be an application error or unknown failure).
pub fn classify_connection_failure(error_msg: &str) -> Option<ConnectionFailureKind> {
    if CONN_REFUSED_PATTERNS.iter().any(|p| error_msg.contains(p)) {
        return Some(ConnectionFailureKind::ConnectionRefused);
    }
    if DNS_FAILURE_PATTERNS.iter().any(|p| error_msg.contains(p)) {
        return Some(ConnectionFailureKind::DnsFailure);
    }
    if AUTH_ERROR_PATTERNS.iter().any(|p| error_msg.contains(p)) {
        return Some(ConnectionFailureKind::AuthError);
    }
    if TIMEOUT_PATTERNS.iter().any(|p| error_msg.contains(p)) {
        return Some(ConnectionFailureKind::Timeout);
    }
    None
}

/// Classify the result of a live call attempt.
///
/// - `Ok(value)` → [`LiveCallOutcome::Success`]
/// - `Err(msg)` where msg matches a connection pattern → [`LiveCallOutcome::ConnectionFailure`]
/// - `Err(msg)` otherwise → [`LiveCallOutcome::AppError`]
pub fn classify_live_call(result: &Result<serde_json::Value, String>) -> LiveCallOutcome {
    match result {
        Ok(_) => LiveCallOutcome::Success,
        Err(msg) => match classify_connection_failure(msg) {
            Some(kind) => LiveCallOutcome::ConnectionFailure { kind },
            None => LiveCallOutcome::AppError {
                message: msg.clone(),
            },
        },
    }
}

// ---------------------------------------------------------------------------
// LiveFirstState — state machine for live-first fallback
// ---------------------------------------------------------------------------

/// State machine tracking whether a live service is available.
///
/// Transitions:
/// - `Untried` + `Success`           → `Available`
/// - `Untried` + `ConnectionFailure` → `Unavailable`
/// - `Untried` + `AppError`          → `Available` (service is reachable)
/// - `Available` + `ConnectionFailure` → `Unavailable`
/// - `Available` + `Success`/`AppError` → `Available`
/// - `Unavailable` is terminal (no retries within a single exploration run)
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum LiveFirstState {
    /// Haven't tried calling the service yet.
    Untried,
    /// At least one successful contact — keep using live calls.
    Available,
    /// Connection failure observed — fall back to synthetic mocks for the
    /// remainder of this exploration run.
    Unavailable,
}

impl LiveFirstState {
    /// Advance the state machine based on a call outcome.
    pub fn transition(self, outcome: &LiveCallOutcome) -> Self {
        match (self, outcome) {
            // Terminal state — no recovery within a run.
            (Self::Unavailable, _) => Self::Unavailable,

            // Connection failure from any non-terminal state → unavailable.
            (_, LiveCallOutcome::ConnectionFailure { .. }) => Self::Unavailable,

            // Success or app error from untried/available → available.
            (Self::Untried | Self::Available, LiveCallOutcome::Success | LiveCallOutcome::AppError { .. }) => {
                Self::Available
            }
        }
    }

    /// Whether we should attempt a live call in this state.
    pub fn should_try_live(self) -> bool {
        matches!(self, Self::Untried | Self::Available)
    }
}

impl Default for LiveFirstState {
    fn default() -> Self {
        Self::Untried
    }
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;

    // -- Serde roundtrip tests --

    #[test]
    fn mock_value_space_serde_roundtrip() {
        let variants = vec![
            MockValueSpace::LiveFirst,
            MockValueSpace::FixedSet {
                values: vec![json!(1), json!("hello"), json!(null)],
            },
            MockValueSpace::Autonomous,
            MockValueSpace::Seeded {
                seed_file: "seeds/api_responses.jsonl".into(),
            },
        ];

        for variant in &variants {
            let json = serde_json::to_string(variant).unwrap();
            let back: MockValueSpace = serde_json::from_str(&json).unwrap();
            assert_eq!(&back, variant, "roundtrip failed for {json}");
        }
    }

    #[test]
    fn live_call_outcome_serde_roundtrip() {
        let variants = vec![
            LiveCallOutcome::Success,
            LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::ConnectionRefused,
            },
            LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::DnsFailure,
            },
            LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::AuthError,
            },
            LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::Timeout,
            },
            LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::Other,
            },
            LiveCallOutcome::AppError {
                message: "404 Not Found".into(),
            },
        ];

        for variant in &variants {
            let json = serde_json::to_string(variant).unwrap();
            let back: LiveCallOutcome = serde_json::from_str(&json).unwrap();
            assert_eq!(&back, variant, "roundtrip failed for {json}");
        }
    }

    #[test]
    fn live_first_state_serde_roundtrip() {
        for state in &[
            LiveFirstState::Untried,
            LiveFirstState::Available,
            LiveFirstState::Unavailable,
        ] {
            let json = serde_json::to_string(state).unwrap();
            let back: LiveFirstState = serde_json::from_str(&json).unwrap();
            assert_eq!(&back, state);
        }
    }

    // -- Classification tests --

    #[test]
    fn classify_connection_refused() {
        assert_eq!(
            classify_connection_failure("Error: connect ECONNREFUSED 127.0.0.1:5432"),
            Some(ConnectionFailureKind::ConnectionRefused)
        );
    }

    #[test]
    fn classify_dns_failure() {
        assert_eq!(
            classify_connection_failure("getaddrinfo ENOTFOUND api.example.com"),
            Some(ConnectionFailureKind::DnsFailure)
        );
    }

    #[test]
    fn classify_auth_error() {
        assert_eq!(
            classify_connection_failure("401 Unauthorized"),
            Some(ConnectionFailureKind::AuthError)
        );
    }

    #[test]
    fn classify_timeout() {
        assert_eq!(
            classify_connection_failure("request timed out after 30s"),
            Some(ConnectionFailureKind::Timeout)
        );
    }

    #[test]
    fn classify_unknown_error_returns_none() {
        assert_eq!(
            classify_connection_failure("something completely different"),
            None
        );
    }

    #[test]
    fn classify_live_call_success() {
        let result: Result<serde_json::Value, String> = Ok(json!({"id": 1}));
        assert_eq!(classify_live_call(&result), LiveCallOutcome::Success);
    }

    #[test]
    fn classify_live_call_connection_failure() {
        let result: Result<serde_json::Value, String> =
            Err("connect ECONNREFUSED 127.0.0.1:3000".into());
        assert!(matches!(
            classify_live_call(&result),
            LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::ConnectionRefused
            }
        ));
    }

    #[test]
    fn classify_live_call_app_error() {
        let result: Result<serde_json::Value, String> = Err("validation failed: name required".into());
        assert!(matches!(
            classify_live_call(&result),
            LiveCallOutcome::AppError { .. }
        ));
    }

    // -- State machine tests --

    #[test]
    fn state_machine_untried_to_available_on_success() {
        let state = LiveFirstState::Untried;
        assert_eq!(
            state.transition(&LiveCallOutcome::Success),
            LiveFirstState::Available
        );
    }

    #[test]
    fn state_machine_untried_to_unavailable_on_conn_failure() {
        let state = LiveFirstState::Untried;
        assert_eq!(
            state.transition(&LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::ConnectionRefused
            }),
            LiveFirstState::Unavailable
        );
    }

    #[test]
    fn state_machine_untried_to_available_on_app_error() {
        let state = LiveFirstState::Untried;
        assert_eq!(
            state.transition(&LiveCallOutcome::AppError {
                message: "500 Internal Server Error".into()
            }),
            LiveFirstState::Available
        );
    }

    #[test]
    fn state_machine_available_stays_on_success() {
        let state = LiveFirstState::Available;
        assert_eq!(
            state.transition(&LiveCallOutcome::Success),
            LiveFirstState::Available
        );
    }

    #[test]
    fn state_machine_available_to_unavailable_on_conn_failure() {
        let state = LiveFirstState::Available;
        assert_eq!(
            state.transition(&LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::Timeout
            }),
            LiveFirstState::Unavailable
        );
    }

    #[test]
    fn state_machine_unavailable_is_terminal() {
        let state = LiveFirstState::Unavailable;
        assert_eq!(
            state.transition(&LiveCallOutcome::Success),
            LiveFirstState::Unavailable
        );
        assert_eq!(
            state.transition(&LiveCallOutcome::ConnectionFailure {
                kind: ConnectionFailureKind::DnsFailure
            }),
            LiveFirstState::Unavailable
        );
        assert_eq!(
            state.transition(&LiveCallOutcome::AppError {
                message: "ok".into()
            }),
            LiveFirstState::Unavailable
        );
    }

    #[test]
    fn should_try_live_reflects_state() {
        assert!(LiveFirstState::Untried.should_try_live());
        assert!(LiveFirstState::Available.should_try_live());
        assert!(!LiveFirstState::Unavailable.should_try_live());
    }

    #[test]
    fn default_state_is_untried() {
        assert_eq!(LiveFirstState::default(), LiveFirstState::Untried);
    }

    // -- Proptest --

    mod proptests {
        use super::super::*;
        use proptest::prelude::*;
        use serde_json::json;

        fn arb_mock_value_space() -> impl Strategy<Value = MockValueSpace> {
            prop_oneof![
                Just(MockValueSpace::LiveFirst),
                prop::collection::vec(
                    prop_oneof![
                        Just(json!(null)),
                        Just(json!(42)),
                        Just(json!("test")),
                        Just(json!(true)),
                    ],
                    0..5,
                )
                .prop_map(|values| MockValueSpace::FixedSet { values }),
                Just(MockValueSpace::Autonomous),
                "[a-z/_]{1,30}".prop_map(|seed_file| MockValueSpace::Seeded { seed_file }),
            ]
        }

        fn arb_connection_failure_kind() -> impl Strategy<Value = ConnectionFailureKind> {
            prop_oneof![
                Just(ConnectionFailureKind::ConnectionRefused),
                Just(ConnectionFailureKind::DnsFailure),
                Just(ConnectionFailureKind::AuthError),
                Just(ConnectionFailureKind::Timeout),
                Just(ConnectionFailureKind::Other),
            ]
        }

        fn arb_live_call_outcome() -> impl Strategy<Value = LiveCallOutcome> {
            prop_oneof![
                Just(LiveCallOutcome::Success),
                arb_connection_failure_kind()
                    .prop_map(|kind| LiveCallOutcome::ConnectionFailure { kind }),
                ".{0,50}".prop_map(|message| LiveCallOutcome::AppError { message }),
            ]
        }

        fn arb_live_first_state() -> impl Strategy<Value = LiveFirstState> {
            prop_oneof![
                Just(LiveFirstState::Untried),
                Just(LiveFirstState::Available),
                Just(LiveFirstState::Unavailable),
            ]
        }

        proptest! {
            #[test]
            fn mock_value_space_roundtrip(mvs in arb_mock_value_space()) {
                let json = serde_json::to_string(&mvs).unwrap();
                let back: MockValueSpace = serde_json::from_str(&json).unwrap();
                prop_assert_eq!(&back, &mvs);
            }

            #[test]
            fn live_call_outcome_roundtrip(outcome in arb_live_call_outcome()) {
                let json = serde_json::to_string(&outcome).unwrap();
                let back: LiveCallOutcome = serde_json::from_str(&json).unwrap();
                prop_assert_eq!(&back, &outcome);
            }

            #[test]
            fn live_first_state_roundtrip(state in arb_live_first_state()) {
                let json = serde_json::to_string(&state).unwrap();
                let back: LiveFirstState = serde_json::from_str(&json).unwrap();
                prop_assert_eq!(&back, &state);
            }

            // Unavailable is terminal: no outcome can leave it.
            #[test]
            fn unavailable_is_terminal(outcome in arb_live_call_outcome()) {
                prop_assert_eq!(
                    LiveFirstState::Unavailable.transition(&outcome),
                    LiveFirstState::Unavailable
                );
            }

            // Connection failure always leads to Unavailable (from any non-terminal state).
            #[test]
            fn conn_failure_always_unavailable(
                state in arb_live_first_state(),
                kind in arb_connection_failure_kind(),
            ) {
                let next = state.transition(&LiveCallOutcome::ConnectionFailure { kind });
                prop_assert_eq!(next, LiveFirstState::Unavailable);
            }

            // Success from a non-Unavailable state always leads to Available.
            #[test]
            fn success_leads_to_available(state in arb_live_first_state()) {
                if state != LiveFirstState::Unavailable {
                    prop_assert_eq!(
                        state.transition(&LiveCallOutcome::Success),
                        LiveFirstState::Available
                    );
                }
            }

            // should_try_live is false iff state is Unavailable.
            #[test]
            fn should_try_live_iff_not_unavailable(state in arb_live_first_state()) {
                prop_assert_eq!(
                    state.should_try_live(),
                    state != LiveFirstState::Unavailable
                );
            }

            // classify_live_call(Ok(_)) is always Success.
            #[test]
            fn classify_ok_is_success(_v in prop_oneof![Just(json!(1)), Just(json!("x"))]) {
                let outcome = classify_live_call(&Ok(_v));
                prop_assert_eq!(outcome, LiveCallOutcome::Success);
            }
        }
    }
}

    #[serde(default = "GeneticConfig::default_max_generations")]
    pub max_generations: u32,

    /// Probability of mutating an individual (0.0–1.0).
    #[serde(default = "GeneticConfig::default_mutation_rate")]
    pub mutation_rate: f64,

    /// Probability of crossover between two individuals (0.0–1.0).
    #[serde(default = "GeneticConfig::default_crossover_rate")]
    pub crossover_rate: f64,

    /// Timeout in seconds for the entire genetic exploration.
    #[serde(default = "GeneticConfig::default_timeout_secs")]
    pub timeout_secs: u32,
}

impl GeneticConfig {
    fn default_population_size() -> u32 { 50 }
    fn default_max_generations() -> u32 { 100 }
    fn default_mutation_rate() -> f64 { 0.3 }
    fn default_crossover_rate() -> f64 { 0.7 }
    fn default_timeout_secs() -> u32 { 300 }
}

impl Default for GeneticConfig {
    fn default() -> Self {
        Self {
            enabled: false,
            population_size: Self::default_population_size(),
            max_generations: Self::default_max_generations(),
            mutation_rate: Self::default_mutation_rate(),
            crossover_rate: Self::default_crossover_rate(),
            timeout_secs: Self::default_timeout_secs(),
        }
    }
}

/// Default settings for all functions.
#[derive(Debug, Clone, Default, Deserialize, Serialize, PartialEq)]
pub struct DefaultsConfig {
    /// Maximum number of iterations per function.
    #[serde(default)]
    pub max_iterations: Option<u32>,

    /// Timeout in seconds per function.
    #[serde(default)]
    pub timeout: Option<u64>,

    /// Path to a setup file, relative to the `.shatter/` directory.
    #[serde(default)]
    pub setup: Option<String>,

    /// Lifecycle level controlling when setup runs (defaults to `Function`).
    #[serde(default)]
    pub setup_level: Option<SetupLevel>,

    /// Timeout in seconds for setup/teardown operations.
    #[serde(default)]
    pub setup_timeout: Option<u64>,

    /// Session-level setup configuration (runs once before any file).
    #[serde(default)]
    pub session_setup: Option<SessionSetupConfig>,

    /// File-level setup: glob pattern → setup file path (relative to `.shatter/`).
    /// Each matching source file gets its own setup invocation at `SetupLevel::File`.
    #[serde(default)]
    pub file_setup: Option<HashMap<String, String>>,

    /// Type-name-to-generator-file mappings (e.g. `"User": "./generators/user.js"`).
    #[serde(default)]
    pub generators: Option<HashMap<String, String>>,

    /// Param-name-to-generator-file mappings (e.g. `"authToken": "./generators/token.js"`).
    #[serde(default)]
    pub param_generators: Option<HashMap<String, String>>,

    /// Per-symbol mock overrides for auto-mocking (e.g. `"db.query": { return_values: [...] }`).
    #[serde(default)]
    pub mocks: Option<HashMap<String, crate::auto_mock::MockOverride>>,

    /// Genetic algorithm explorer settings.
    #[serde(default)]
    pub genetic: Option<GeneticConfig>,
}


/// Per-function configuration, matched by glob pattern against function identifiers.
#[derive(Debug, Clone, Default, Deserialize, Serialize, PartialEq)]
pub struct FunctionConfig {
    /// Maximum iterations for this function.
    #[serde(default)]
    pub max_iterations: Option<u32>,

    /// Timeout in seconds for this function.
    #[serde(default)]
    pub timeout: Option<u64>,

    /// Path to a candidate inputs JSON file, relative to the `.shatter/` directory.
    #[serde(default)]
    pub inputs: Option<String>,

    /// Skip this function entirely.
    #[serde(default)]
    pub skip: Option<bool>,

    /// Path to a setup file, relative to the `.shatter/` directory.
    #[serde(default)]
    pub setup: Option<String>,

    /// Lifecycle level controlling when setup runs (overrides default).
    #[serde(default)]
    pub setup_level: Option<SetupLevel>,

    /// Timeout in seconds for setup/teardown operations (overrides default).
    #[serde(default)]
    pub setup_timeout: Option<u64>,

    /// Type-name-to-generator-file mappings, overriding defaults.
    #[serde(default)]
    pub generators: Option<HashMap<String, String>>,

    /// Param-name-to-generator-file mappings, overriding defaults.
    #[serde(default)]
    pub param_generators: Option<HashMap<String, String>>,

    /// Per-symbol mock overrides, overriding defaults.
    #[serde(default)]
    pub mocks: Option<HashMap<String, crate::auto_mock::MockOverride>>,

    /// Genetic algorithm explorer settings, overriding defaults.
    #[serde(default)]
    pub genetic: Option<GeneticConfig>,
}

/// A single candidate input for a function.
#[derive(Debug, Clone, Deserialize, Serialize, PartialEq)]
pub struct CandidateInput {
    /// The argument values to pass to the function.
    pub args: Vec<serde_json::Value>,

    /// Optional human-readable label describing this input.
    #[serde(default)]
    pub label: Option<String>,
}

/// A user declaration that a specific field is (or is not) nondeterministic.
#[derive(Debug, Clone, Deserialize, Serialize, PartialEq)]
pub struct NondeterminismDeclaration {
    /// Function name or pattern (e.g. `"createUser"`).
    pub function: String,
    /// JSONPath to the field (e.g. `"$.id"`).
    pub path: String,
    /// Human-readable explanation of why this field is/isn't nondeterministic.
    pub reason: String,
}

/// User-declared nondeterminism configuration.
///
/// `confirmed` entries become `NondeterminismEvidence::UserDeclared` (highest precedence).
/// `rejected` entries suppress re-flagging by heuristics.
#[derive(Debug, Clone, Default, Deserialize, Serialize, PartialEq)]
pub struct NondeterminismConfig {
    #[serde(default)]
    pub confirmed: Vec<NondeterminismDeclaration>,
    #[serde(default)]
    pub rejected: Vec<NondeterminismDeclaration>,
}

/// Resolved configuration for a specific function, after merging hierarchical configs.
#[derive(Debug, Clone)]
pub struct ResolvedFunctionConfig {
    /// Maximum iterations (from config or CLI default).
    pub max_iterations: u32,

    /// Timeout in seconds (from config or CLI default).
    pub timeout: u64,

    /// Whether to skip this function.
    pub skip: bool,

    /// User-provided candidate inputs, if any.
    pub candidate_inputs: Vec<CandidateInput>,

    /// Resolved absolute path to the setup file, if any.
    pub setup: Option<PathBuf>,

    /// Lifecycle level controlling when setup runs (defaults to `Function`).
    pub setup_level: SetupLevel,

    /// Timeout in seconds for setup/teardown operations.
    pub setup_timeout: u64,

    /// Session-level setup configuration, if any.
    pub session_setup: Option<SessionSetupConfig>,

    /// File-level setup: glob pattern → resolved absolute path to setup file.
    pub file_setup: HashMap<String, PathBuf>,

    /// Merged type-name-to-generator-file mappings (absolute paths).
    pub generators: HashMap<String, PathBuf>,

    /// Merged param-name-to-generator-file mappings (absolute paths).
    pub param_generators: HashMap<String, PathBuf>,

    /// Merged per-symbol mock overrides for auto-mocking.
    pub mock_overrides: HashMap<String, crate::auto_mock::MockOverride>,
}

/// A config file found during hierarchical discovery, paired with its directory.
#[derive(Debug, Clone)]
struct DiscoveredConfig {
    /// The `.shatter/` directory containing this config.
    shatter_dir: PathBuf,
    /// The parsed config.
    config: ShatterConfig,
}

/// Parse a `.shatter/config.yaml` file.
pub fn parse_config(path: &Path) -> Result<ShatterConfig, ConfigError> {
    let contents = std::fs::read_to_string(path).map_err(|e| ConfigError::Io {
        path: path.to_path_buf(),
        source: e,
    })?;
    let config: ShatterConfig =
        serde_yaml::from_str(&contents).map_err(|e| ConfigError::Parse {
            path: path.to_path_buf(),
            source: e,
        })?;
    Ok(config)
}

/// Parse a candidate inputs JSON file.
pub fn parse_candidate_inputs(path: &Path) -> Result<Vec<CandidateInput>, ConfigError> {
    let contents = std::fs::read_to_string(path).map_err(|e| ConfigError::InputIo {
        path: path.to_path_buf(),
        source: e,
    })?;
    let inputs: Vec<CandidateInput> =
        serde_json::from_str(&contents).map_err(|e| ConfigError::InputParse {
            path: path.to_path_buf(),
            source: e,
        })?;
    Ok(inputs)
}

/// Discover `.shatter/config.yaml` files by walking upward from `start_dir`.
///
/// Returns configs ordered from nearest (highest priority) to farthest (lowest priority).
pub fn discover_configs(start_dir: &Path) -> Result<Vec<ShatterConfig>, ConfigError> {
    let discovered = discover_configs_with_paths(start_dir)?;
    Ok(discovered.into_iter().map(|d| d.config).collect())
}

/// Internal: discover configs with their `.shatter/` directory paths preserved.
fn discover_configs_with_paths(start_dir: &Path) -> Result<Vec<DiscoveredConfig>, ConfigError> {
    let mut configs = Vec::new();
    let mut current = Some(start_dir.to_path_buf());

    while let Some(dir) = current {
        let shatter_dir = dir.join(".shatter");
        let config_path = shatter_dir.join("config.yaml");

        if config_path.is_file() {
            let config = parse_config(&config_path)?;
            configs.push(DiscoveredConfig {
                shatter_dir,
                config,
            });
        }

        current = dir.parent().map(Path::to_path_buf);
    }

    Ok(configs)
}

/// Merge multiple configs where the first config in the slice has highest priority.
///
/// For defaults, the nearest non-None value wins.
/// For function patterns, the nearest matching pattern wins.
pub fn merge_configs(configs: &[ShatterConfig]) -> ShatterConfig {
    if configs.is_empty() {
        return ShatterConfig::default();
    }
    if configs.len() == 1 {
        return configs[0].clone();
    }

    // Merge defaults: nearest non-None wins.
    let mut max_iterations = None;
    let mut timeout = None;
    let mut setup = None;
    let mut setup_level = None;
    let mut setup_timeout = None;
    let mut session_setup = None;

    // Merge generators and file_setup maps: start from farthest, overlay nearer.
    // This lets a near config override specific keys while inheriting the rest.
    let mut generators: Option<HashMap<String, String>> = None;
    let mut param_generators: Option<HashMap<String, String>> = None;
    let mut file_setup: Option<HashMap<String, String>> = None;

    for config in configs.iter().rev() {
        if let Some(ref g) = config.defaults.generators {
            generators.get_or_insert_with(HashMap::new).extend(
                g.iter().map(|(k, v)| (k.clone(), v.clone())),
            );
        }
        if let Some(ref pg) = config.defaults.param_generators {
            param_generators.get_or_insert_with(HashMap::new).extend(
                pg.iter().map(|(k, v)| (k.clone(), v.clone())),
            );
        }
        if let Some(ref fs) = config.defaults.file_setup {
            file_setup.get_or_insert_with(HashMap::new).extend(
                fs.iter().map(|(k, v)| (k.clone(), v.clone())),
            );
        }
    }

    for config in configs {
        if max_iterations.is_none() {
            max_iterations = config.defaults.max_iterations;
        }
        if timeout.is_none() {
            timeout = config.defaults.timeout;
        }
        if setup.is_none() {
            setup = config.defaults.setup.clone();
        }
        if setup_level.is_none() {
            setup_level = config.defaults.setup_level;
        }
        if setup_timeout.is_none() {
            setup_timeout = config.defaults.setup_timeout;
        }
        if session_setup.is_none() {
            session_setup = config.defaults.session_setup.clone();
        }
    }

    // Merge function configs: collect all, nearest first (already in order).
    // Later entries only fill in if the pattern hasn't been seen.
    let mut functions: HashMap<String, FunctionConfig> = HashMap::new();
    for config in configs {
        for (pattern, func_config) in &config.functions {
            functions.entry(pattern.clone()).or_insert_with(|| func_config.clone());
        }
    }

    let mut opaque_types = Vec::new();
    for config in configs {
        for t in &config.opaque_types {
            if !opaque_types.contains(t) {
                opaque_types.push(t.clone());
            }
        }
    }

    // Merge nondeterminism declarations: union all confirmed/rejected, dedup by (function, path).
    let mut confirmed = Vec::<NondeterminismDeclaration>::new();
    let mut rejected = Vec::<NondeterminismDeclaration>::new();
    let mut has_any = false;
    for config in configs {
        if let Some(ref nd) = config.nondeterminism {
            has_any = true;
            for decl in &nd.confirmed {
                if !confirmed.iter().any(|d| d.function == decl.function && d.path == decl.path) {
                    confirmed.push(decl.clone());
                }
            }
            for decl in &nd.rejected {
                if !rejected.iter().any(|d| d.function == decl.function && d.path == decl.path) {
                    rejected.push(decl.clone());
                }
            }
        }
    }
    let nondeterminism = if has_any {
        Some(NondeterminismConfig { confirmed, rejected })
    } else {
        None
    };

    ShatterConfig {
        defaults: DefaultsConfig {
            max_iterations,
            timeout,
            setup,
            setup_level,
            setup_timeout,
            session_setup,
            file_setup,
            generators,
            param_generators,
            mocks: None,
            genetic: None,
        },
        functions,
        opaque_types,
        nondeterminism,
    }
}

/// Resolve the effective configuration for a specific function identifier.
///
/// `function_id` is typically in `"file:function"` format.
/// `configs` should be ordered nearest-first (as returned by `discover_configs`).
/// `cli_max_iterations` and `cli_timeout` are the CLI-provided defaults.
pub fn resolve_function_config(
    function_id: &str,
    configs: &[ShatterConfig],
    cli_max_iterations: u32,
    cli_timeout: u64,
) -> Result<ResolvedFunctionConfig, ConfigError> {
    let merged = merge_configs(configs);
    resolve_from_merged(function_id, &merged, cli_max_iterations, cli_timeout)
}

/// Resolve config for a function from an already-merged config.
fn resolve_from_merged(
    function_id: &str,
    config: &ShatterConfig,
    cli_max_iterations: u32,
    cli_timeout: u64,
) -> Result<ResolvedFunctionConfig, ConfigError> {
    // Find the first matching function pattern.
    let mut func_config: Option<&FunctionConfig> = None;

    for (pattern, fc) in &config.functions {
        let matcher = compile_pattern(pattern)?;
        if matcher.is_match(function_id) {
            func_config = Some(fc);
            break;
        }
    }

    // Resolution order: function config > defaults > CLI flags
    let max_iterations = func_config
        .and_then(|fc| fc.max_iterations)
        .or(config.defaults.max_iterations)
        .unwrap_or(cli_max_iterations);

    let timeout = func_config
        .and_then(|fc| fc.timeout)
        .or(config.defaults.timeout)
        .unwrap_or(cli_timeout);

    let skip = func_config
        .and_then(|fc| fc.skip)
        .unwrap_or(false);

    let setup_level = func_config
        .and_then(|fc| fc.setup_level)
        .or(config.defaults.setup_level)
        .unwrap_or(SetupLevel::Function);

    let setup_timeout = func_config
        .and_then(|fc| fc.setup_timeout)
        .or(config.defaults.setup_timeout)
        .unwrap_or(DEFAULT_SETUP_TIMEOUT_SECS);

    // Merge mock overrides: defaults first, then function-level overrides on top.
    let mut mock_overrides: HashMap<String, crate::auto_mock::MockOverride> = config
        .defaults
        .mocks
        .clone()
        .unwrap_or_default();
    if let Some(fc) = func_config
        && let Some(ref func_mocks) = fc.mocks
    {
        for (k, v) in func_mocks {
            mock_overrides.insert(k.clone(), v.clone());
        }
    }

    Ok(ResolvedFunctionConfig {
        max_iterations,
        timeout,
        skip,
        candidate_inputs: Vec::new(),
        // Setup and generator paths are resolved to absolute paths by
        // resolve_function_config_with_inputs, which has access to .shatter/ dirs.
        setup: None,
        setup_level,
        setup_timeout,
        session_setup: config.defaults.session_setup.clone(),
        file_setup: HashMap::new(),
        generators: HashMap::new(),
        param_generators: HashMap::new(),
        mock_overrides,
    })
}

/// Resolve config for a function and load candidate inputs if specified.
///
/// `shatter_dir` is the `.shatter/` directory used to resolve relative input paths.
/// If `explicit_inputs` is provided (from `--inputs` CLI flag), it takes precedence.
pub fn resolve_function_config_with_inputs(
    function_id: &str,
    start_dir: &Path,
    explicit_inputs: Option<&Path>,
    cli_max_iterations: u32,
    cli_timeout: u64,
) -> Result<ResolvedFunctionConfig, ConfigError> {
    let discovered = discover_configs_with_paths(start_dir)?;
    let configs: Vec<ShatterConfig> = discovered.iter().map(|d| d.config.clone()).collect();
    let merged = merge_configs(&configs);

    let mut resolved = resolve_from_merged(function_id, &merged, cli_max_iterations, cli_timeout)?;

    // Load candidate inputs.
    if let Some(inputs_path) = explicit_inputs {
        resolved.candidate_inputs = parse_candidate_inputs(inputs_path)?;
    } else {
        // Check function config for an inputs path.
        for dc in &discovered {
            for (pattern, fc) in &dc.config.functions {
                let matcher = compile_pattern(pattern)?;
                if matcher.is_match(function_id)
                    && let Some(inputs_rel) = &fc.inputs
                {
                    let inputs_path = dc.shatter_dir.join(inputs_rel);
                    if inputs_path.is_file() {
                        resolved.candidate_inputs =
                            parse_candidate_inputs(&inputs_path)?;
                    }
                    break;
                }
            }
        }
    }

    // Resolve setup file path: function-level > defaults, nearest config wins.
    for dc in &discovered {
        if resolved.setup.is_some() {
            break;
        }
        for (pattern, fc) in &dc.config.functions {
            let matcher = compile_pattern(pattern)?;
            if matcher.is_match(function_id)
                && let Some(setup_rel) = &fc.setup
            {
                resolved.setup = Some(dc.shatter_dir.join(setup_rel));
                break;
            }
        }
        if resolved.setup.is_none()
            && let Some(setup_rel) = &dc.config.defaults.setup
        {
            resolved.setup = Some(dc.shatter_dir.join(setup_rel));
        }
    }

    // Resolve file_setup: walk farthest-to-nearest so nearer configs override.
    for dc in discovered.iter().rev() {
        if let Some(ref fs) = dc.config.defaults.file_setup {
            for (glob_pattern, setup_rel) in fs {
                resolved.file_setup.insert(glob_pattern.clone(), dc.shatter_dir.join(setup_rel));
            }
        }
    }

    // Resolve generators: merge defaults then overlay function-level.
    // Walk farthest-to-nearest so nearer configs override.
    for dc in discovered.iter().rev() {
        if let Some(ref g) = dc.config.defaults.generators {
            for (type_name, gen_rel) in g {
                resolved.generators.insert(type_name.clone(), dc.shatter_dir.join(gen_rel));
            }
        }
        if let Some(ref pg) = dc.config.defaults.param_generators {
            for (param_name, gen_rel) in pg {
                resolved.param_generators.insert(param_name.clone(), dc.shatter_dir.join(gen_rel));
            }
        }
    }
    // Function-level generators overlay defaults (nearest matching function wins).
    for dc in &discovered {
        for (pattern, fc) in &dc.config.functions {
            let matcher = compile_pattern(pattern)?;
            if matcher.is_match(function_id) {
                if let Some(ref g) = fc.generators {
                    for (type_name, gen_rel) in g {
                        resolved.generators.insert(type_name.clone(), dc.shatter_dir.join(gen_rel));
                    }
                }
                if let Some(ref pg) = fc.param_generators {
                    for (param_name, gen_rel) in pg {
                        resolved.param_generators.insert(param_name.clone(), dc.shatter_dir.join(gen_rel));
                    }
                }
                break;
            }
        }
    }

    Ok(resolved)
}

fn compile_pattern(pattern: &str) -> Result<GlobMatcher, ConfigError> {
    let glob = Glob::new(pattern).map_err(|e| ConfigError::InvalidPattern {
        pattern: pattern.to_string(),
        source: e,
    })?;
    Ok(glob.compile_matcher())
}

#[cfg(test)]
mod tests {
