        let to_scope = |fixtures: Vec<MockFixture>| MockFixtureScope {
            fixtures: fixtures
                .into_iter()
                .map(|f| (f.symbol.clone(), f))
                .collect(),
        };

        MockFixtureConfig {
            global: to_scope(global),
            files: files
                .into_iter()
                .map(|(k, v)| (k.to_string(), to_scope(v)))
                .collect(),
            functions: functions
                .into_iter()
                .map(|(k, v)| (k.to_string(), to_scope(v)))
                .collect(),
        }
    }

